elements.content:
flowchart LR
  U[User Prompt] --> G[API Gateway]
  G --> R[Router]
  R --> I[Model Interface]
  I --> C[Claude Model]
  C --> B[Response Builder]
  B --> U2[User Reply]
  M[(Context Store)] -. context .-> I
  B -. save turn .-> M

  classDef active fill:#d97706,stroke:#fff7ed,color:#fff,stroke-width:2px;
  classDef base fill:#1f2937,stroke:#475569,color:#f8fafc;
  classDef store fill:#3b2f2f,stroke:#f59e0b,color:#fff7ed;
  class U,G,R,I,C,B,U2 base;
  class M store;
  class G active;

flowchart LR
  U[User Prompt] --> G[API Gateway]
  G --> A{Auth OK?}
  A -->|yes| L{Within Limit?}
  A -->|no| X[Reject Request]
  L -->|yes| R[Router]
  L -->|no| Y[Slow Down]

  classDef active fill:#d97706,stroke:#fff7ed,color:#fff,stroke-width:2px;
  classDef decision fill:#312e81,stroke:#818cf8,color:#eef2ff;
  classDef base fill:#1f2937,stroke:#475569,color:#f8fafc;
  classDef reject fill:#7f1d1d,stroke:#fca5a5,color:#fff;
  class U,R base;
  class G active;
  class A,L decision;
  class X,Y reject;

flowchart LR
  T1[Turn 1] --> M[(Memory Store)]
  T2[Turn 2] --> M
  T3[Current Prompt] --> C[Context Pack]
  M --> C
  C --> I[Model Interface]
  I --> B[Response Builder]
  B -. save latest turn .-> M

  classDef active fill:#d97706,stroke:#fff7ed,color:#fff,stroke-width:2px;
  classDef base fill:#1f2937,stroke:#475569,color:#f8fafc;
  classDef store fill:#3b2f2f,stroke:#f59e0b,color:#fff7ed;
  classDef context fill:#064e3b,stroke:#34d399,color:#ecfdf5;
  class T1,T2,T3,I,B base;
  class M store;
  class C active,context;

flowchart LR
  G[API Gateway] --> P[Parser]
  P --> V[Validator]
  V --> O[Orchestrator]
  O --> I[Model Interface]
  I --> RB[Response Builder]
  RB --> OUT[Final Reply]

  classDef active fill:#d97706,stroke:#fff7ed,color:#fff,stroke-width:2px;
  classDef base fill:#1f2937,stroke:#475569,color:#f8fafc;
  classDef reply fill:#0f766e,stroke:#5eead4,color:#ecfeff;
  class G,I base;
  class P,V,O,RB active;
  class OUT reply;

flowchart LR
  REQ[Incoming Request] --> AUTH[Authentication]
  AUTH --> LIMIT[Rate Limit]
  LIMIT --> CALL[Service Call]
  CALL --> OK{Success?}
  OK -->|yes| LOG[Write Logs]
  OK -->|no| RETRY[Retry or Fail Safe]
  RETRY --> LOG
  LOG --> RESP[Return Response]

  classDef active fill:#d97706,stroke:#fff7ed,color:#fff,stroke-width:2px;
  classDef base fill:#1f2937,stroke:#475569,color:#f8fafc;
  classDef decision fill:#312e81,stroke:#818cf8,color:#eef2ff;
  classDef safety fill:#7c2d12,stroke:#fdba74,color:#fff7ed;
  class REQ,CALL,RESP base;
  class AUTH,LIMIT,LOG safety;
  class OK decision;
  class RETRY active;
